  function prepareFormModal(trigger) {
    if (!formModal || !formTitleNode || !formSubmitNode) {
      return;
    }
    const actionText = (trigger?.textContent || "").trim() || "编辑";
    const pageTitle = (pageTitleNode?.textContent || "").trim();
    const mode = actionText.indexOf("新增") !== -1 ? "新增" : "编辑";
    formTitleNode.textContent = pageTitle ? mode + pageTitle : mode + "信息";
    formSubmitNode.textContent = "保存";

    const fields = Array.from(formModal.querySelectorAll("[data-form-field]"));
    if (mode === "新增") {
      fields.forEach((field) => {
        field.textContent = field.dataset.placeholder || "";
      });
      return;
    }

    const rowState = rowStateMap.get(activeRowId) || {};
    const formValues = rowState.formValues || {};
    fields.forEach((field) => {
      const label = field.dataset.formField || "";
      const value = formValues[label];
      field.textContent = value || field.dataset.placeholder || "";
    });
  }

  function prepareCapabilityAuthModal(trigger) {
    const modal = modals.get("capability-auth");
    if (!modal) {
      return;
    }
    const rowId = trigger?.dataset?.rowId || activeRowId;
    const rowState = rowStateMap.get(rowId) || {};
    const record = rowState.record || {};
    const partnerNameNode = modal.querySelector("[data-capability-partner-name]");
    if (partnerNameNode) {
      partnerNameNode.textContent = record.name || "--";
    }

    const notifyChannelNode = modal.querySelector("[data-capability-notify-channel]");
    if (notifyChannelNode) {
      notifyChannelNode.value = "站内信通知";
    }

    const accountSelectNode = modal.querySelector("[data-capability-account-select]");
    if (accountSelectNode) {
      const values = [];
      const seen = new Set();
      parseIpValues(record.account_options).forEach((item) => {
        if (!seen.has(item)) {
          seen.add(item);
          values.push(item);
        }
      });
      [record.system_account, record.portal_account].forEach((item) => {
        const value = String(item || "").trim();
        if (value && !seen.has(value)) {
          seen.add(value);
          values.push(value);
        }
      });
      if (values.length === 0) {
        accountSelectNode.innerHTML = "<option value=''>暂无可选帐号</option>";
        accountSelectNode.value = "";
      } else {
        accountSelectNode.innerHTML = values
          .map((value) => "<option value='" + escapeHtml(value) + "'>" + escapeHtml(value) + "</option>")
          .join("");
        accountSelectNode.value = values[0];
      }
    }

    setCapabilityNotifyToggle(modal, true);

    const searchNode = modal.querySelector("[data-cap-search]");
    if (searchNode) {
      searchNode.textContent = "";
    }
    modal.querySelectorAll("[data-cap-item]").forEach((item) => {
      item.classList.remove("is-hidden");
    });
    filterCapabilityItems();
  }

